9283   // somewhere.
9284   bool IsAllowedSingleBVNode =
9285       VectorizableTree.size() > 1 ||
9286       (VectorizableTree.size() == 1 && VectorizableTree.front()->getOpcode() &&
9287        VectorizableTree.front()->getOpcode() != Instruction::PHI &&
9288        VectorizableTree.front()->getOpcode() != Instruction::GetElementPtr &&
9289        allSameBlock(VectorizableTree.front()->Scalars));
